import React, { useEffect, useState } from 'react';
import './styles/App.css';
import axios from 'axios';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import LoginPage from './pages/Login';
import Countries from './pages/Countries';
import Admin from './pages/Admin';
function decodeUnicode(str) {
  return str.replace(/\\u([\dA-F]{4})/gi, (match, grp) => {
    return String.fromCharCode(parseInt(grp, 16));
  });
}
function App() {
  const [countries, setCountries] = useState([]);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const handleLogin = (newToken) => {
    setToken(newToken);
    localStorage.setItem('token', newToken);
};

const handleLogout = () => {
    setToken(null);
    localStorage.removeItem('token');
};
  useEffect(() => {
    axios.get('http://192.168.66.59:5000/api/countries')
      .then(response => {
        setCountries(response.data); // name 
      })
      .catch(error => {
        console.error('There was an error fetching countries!', error);
      });
  }, []);

  return (
    <Router>
    <Routes>
        <Route path="/login" element={<LoginPage setToken={handleLogin} />} />
        <Route path="/" element={token ? <Countries token={token} /> : <Navigate to="/login" />} />
        <Route path="/admin" element={token ? <Admin token={token} /> : <Navigate to="/login" />} />
    </Routes>
</Router>
  );
}
export default App;
